// types/database.ts
import { Tables } from '@/lib/supabase/database.types'
export type ProfileRow = Tables<'profiles'>
export interface MeetingRow { id: string; host_id: string; title: string; ... }
// (신규 테이블 7개 동일 패턴)

// types/domain.ts
export const APPROVAL_TYPE = { AUTO: 'auto', MANUAL: 'manual' } as const
export type ApprovalType = (typeof APPROVAL_TYPE)[keyof typeof APPROVAL_TYPE]
// (나머지 상수 동일 패턴)
export interface MeetingWithHost extends MeetingRow { host: ProfileRow }
export interface MeetingCardData { id: string; title: string; eventAt: Date; approvedCount: number; maxParticipants: number | null; pendingCount: number; status: MeetingStatus }

// types/index.ts
export * from './database'
export * from './domain'

// lib/validations/meeting.ts
import { z } from 'zod'
export const meetingSchema = z.object({
  title: z.string().min(1, { message: '모임 제목을 입력해주세요' }),
  description: z.string().optional(),
  event_at: z.string().min(1, { message: '모임 날짜를 선택해주세요' }),
  location: z.string().optional(),
  max_participants: z.coerce.number().int().min(1, { message: '최소 1명 이상이어야 합니다' }).optional(),
  entry_fee: z.coerce.number().int().min(0, { message: '참가비는 0원 이상이어야 합니다' }),
  approval_type: z.union([z.literal('auto'), z.literal('manual')])
})
export type MeetingFormValues = z.infer<typeof meetingSchema>
export const meetingUpdateSchema = meetingSchema.partial()
export type MeetingUpdateFormValues = z.infer<typeof meetingUpdateSchema>

// lib/validations/notice.ts - 동일 패턴

// lib/validations/carpool.ts
import { z } from 'zod'
export const carpoolDriverSchema = z.object({
  departure_location: z.string().min(1, { message: '출발지를 입력해주세요' }),
  departure_at: z.string().min(1, { message: '출발 시간을 선택해주세요' }),
  available_seats: z.coerce.number().int().min(1, { message: '최소 1석 이상이어야 합니다' }).max(8, { message: '최대 8석까지 등록 가능합니다' })
})
export type CarpoolDriverFormValues = z.infer<typeof carpoolDriverSchema>
export const carpoolPassengerSchema = z.object({
  carpool_driver_id: z.string().uuid({ message: '유효하지 않은 드라이버 ID입니다' })
})
export type CarpoolPassengerFormValues = z.infer<typeof carpoolPassengerSchema>

// lib/validations/settlement.ts
export const settlementItemSchema = z.object({
  label: z.string().min(1, { message: '항목명을 입력해주세요' }),
  amount: z.coerce.number().int().min(1, { message: '금액은 1원 이상이어야 합니다' })
})
export const settlementSchema = z.object({
  total_amount: z.coerce.number().int().min(1, { message: '총 금액을 입력해주세요' }),
  split_type: z.union([z.literal('equal'), z.literal('manual')]),
  items: z.array(settlementItemSchema).min(1, { message: '항목을 최소 1개 입력해주세요' })
})
export type SettlementFormValues = z.infer<typeof settlementSchema>
